namespace sv_40f89141269a4c57b29951004fbd10e6.Client.Models;

public class Shipment
{
    public string TrackingNumber { get; set; } = string.Empty;
    public string Status { get; set; } = string.Empty;
    public string Location { get; set; } = string.Empty;
    public DateTimeOffset EstimatedDelivery { get; set; }
    public List<StatusUpdate> StatusUpdates { get; set; } = new();
}

public class StatusUpdate
{
    public string Description { get; set; } = string.Empty;
    public string Location { get; set; } = string.Empty;
    public DateTimeOffset Timestamp { get; set; }
}

using sv_40f89141269a4c57b29951004fbd10e6.Client.Models;

namespace sv_40f89141269a4c57b29951004fbd10e6.Client.Services;

public interface IShipmentService
{
    Task<Shipment> GetShipmentAsync(string trackingNumber, CancellationToken ct);
}

using sv_40f89141269a4c57b29951004fbd10e6.Client.Models;
using sv_40f89141269a4c57b29951004fbd10e6.Client.Services;

namespace sv_40f89141269a4c57b29951004fbd10e6.Services;

public class ShipmentService : IShipmentService
{
    private static readonly Dictionary<string, Shipment> SeedData = new(StringComparer.OrdinalIgnoreCase)
    {
        ["TRK-001"] = new Shipment
        {
            TrackingNumber = "TRK-001",
            Status = "In Transit",
            Location = "Chicago, IL",
            EstimatedDelivery = DateTimeOffset.UtcNow.AddDays(2),
            StatusUpdates = new List<StatusUpdate>
            {
                new() { Description = "Package picked up", Location = "New York, NY", Timestamp = DateTimeOffset.UtcNow.AddDays(-3) },
                new() { Description = "Departed facility", Location = "New York, NY", Timestamp = DateTimeOffset.UtcNow.AddDays(-2) },
                new() { Description = "Arrived at sorting center", Location = "Chicago, IL", Timestamp = DateTimeOffset.UtcNow.AddDays(-1) },
                new() { Description = "In transit to destination", Location = "Chicago, IL", Timestamp = DateTimeOffset.UtcNow.AddHours(-6) }
            }
        },
        ["TRK-002"] = new Shipment
        {
            TrackingNumber = "TRK-002",
            Status = "Delivered",
            Location = "San Francisco, CA",
            EstimatedDelivery = DateTimeOffset.UtcNow.AddDays(-1),
            StatusUpdates = new List<StatusUpdate>
            {
                new() { Description = "Package picked up", Location = "Seattle, WA", Timestamp = DateTimeOffset.UtcNow.AddDays(-5) },
                new() { Description = "In transit", Location = "Portland, OR", Timestamp = DateTimeOffset.UtcNow.AddDays(-4) },
                new() { Description = "Out for delivery", Location = "San Francisco, CA", Timestamp = DateTimeOffset.UtcNow.AddDays(-1) },
                new() { Description = "Delivered", Location = "San Francisco, CA", Timestamp = DateTimeOffset.UtcNow.AddDays(-1).AddHours(3) }
            }
        },
        ["TRK-003"] = new Shipment
        {
            TrackingNumber = "TRK-003",
            Status = "Processing",
            Location = "Dallas, TX",
            EstimatedDelivery = DateTimeOffset.UtcNow.AddDays(5),
            StatusUpdates = new List<StatusUpdate>
            {
                new() { Description = "Label created", Location = "Dallas, TX", Timestamp = DateTimeOffset.UtcNow.AddHours(-12) },
                new() { Description = "Awaiting pickup", Location = "Dallas, TX", Timestamp = DateTimeOffset.UtcNow.AddHours(-6) }
            }
        }
    };

    public async Task<Shipment> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        await Task.Delay(1500, ct);

        if (SeedData.TryGetValue(trackingNumber, out var shipment))
        {
            return shipment;
        }

        throw new KeyNotFoundException($"Shipment with tracking number '{trackingNumber}' was not found.");
    }
}

using System.Net;
using System.Net.Http.Json;
using sv_40f89141269a4c57b29951004fbd10e6.Client.Models;

namespace sv_40f89141269a4c57b29951004fbd10e6.Client.Services;

/// <summary>
/// HttpClient-based implementation used when running on WebAssembly.
/// Calls back to the server API endpoint.
/// </summary>
public class ShipmentServiceClient : IShipmentService
{
    private readonly HttpClient _httpClient;

    public ShipmentServiceClient(HttpClient httpClient)
    {
        _httpClient = httpClient;
    }

    public async Task<Shipment> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        var response = await _httpClient.GetAsync($"api/shipments/{Uri.EscapeDataString(trackingNumber)}", ct);

        if (response.StatusCode == HttpStatusCode.NotFound)
        {
            throw new KeyNotFoundException($"Shipment with tracking number '{trackingNumber}' was not found.");
        }

        response.EnsureSuccessStatusCode();

        var shipment = await response.Content.ReadFromJsonAsync<Shipment>(ct)
            ?? throw new InvalidOperationException("Received empty response from server.");

        return shipment;
    }
}

@page "/shipments/{TrackingNumber}"
@rendermode InteractiveAuto
@using sv_40f89141269a4c57b29951004fbd10e6.Client.Models
@using sv_40f89141269a4c57b29951004fbd10e6.Client.Services
@inject IShipmentService ShipmentService
@inject ILogger<ShipmentTracking> Logger
@implements IDisposable

<PageTitle>Shipment @TrackingNumber</PageTitle>

@if (_loading)
{
    <div class="loading-placeholder">
        <p>Loading shipment details for <strong>@TrackingNumber</strong>...</p>
    </div>
}
else if (_errorMessage is not null)
{
    <div class="error-container">
        <p class="error-message">@_errorMessage</p>
        <button @onclick="RetryLoad">Retry</button>
    </div>
}
else if (_shipment is not null)
{
    <div class="shipment-details">
        <h2>Shipment @_shipment.TrackingNumber</h2>
        <dl>
            <dt>Status</dt>
            <dd>@_shipment.Status</dd>
            <dt>Location</dt>
            <dd>@_shipment.Location</dd>
            <dt>Estimated Delivery</dt>
            <dd>@_shipment.EstimatedDelivery.ToString("f")</dd>
        </dl>

        <h3>Status Updates</h3>
        <ul class="status-updates">
            @foreach (var update in _shipment.StatusUpdates)
            {
                <li>
                    <strong>@update.Timestamp.ToString("g")</strong> —
                    @update.Description (@update.Location)
                </li>
            }
        </ul>
    </div>
}

@code {
    [Parameter]
    public string TrackingNumber { get; set; } = string.Empty;

    private Shipment? _shipment;
    private bool _loading;
    private string? _errorMessage;
    private CancellationTokenSource? _cts;

    protected override async Task OnParametersSetAsync()
    {
        await LoadShipmentAsync();
    }

    private async Task LoadShipmentAsync()
    {
        // Cancel any in-flight request
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = new CancellationTokenSource();
        var ct = _cts.Token;

        _loading = true;
        _errorMessage = null;
        _shipment = null;
        StateHasChanged();

        try
        {
            _shipment = await ShipmentService.GetShipmentAsync(TrackingNumber, ct);
        }
        catch (OperationCanceledException) when (ct.IsCancellationRequested)
        {
            // Navigation changed or component disposed — do nothing
            return;
        }
        catch (TaskCanceledException ex) when (ex.InnerException is TimeoutException || !ct.IsCancellationRequested)
        {
            Logger.LogError(ex, "Timeout loading shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "The request timed out. Please try again.";
        }
        catch (TimeoutException ex)
        {
            Logger.LogError(ex, "Timeout loading shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "The request timed out. Please try again.";
        }
        catch (KeyNotFoundException ex)
        {
            Logger.LogWarning(ex, "Shipment not found: {TrackingNumber}", TrackingNumber);
            _errorMessage = $"Shipment '{TrackingNumber}' was not found.";
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Error loading shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "Something went wrong while loading shipment details. Please try again.";
        }
        finally
        {
            _loading = false;
            StateHasChanged();
        }
    }

    private async Task RetryLoad()
    {
        await LoadShipmentAsync();
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

