using sv_40f89141269a4c57b29951004fbd10e6.Client.Models;

namespace sv_40f89141269a4c57b29951004fbd10e6.Client.Services;

/// <summary>
/// HttpClient-based implementation used when running on WebAssembly.
/// Calls back to the server API endpoint.
/// </summary>
public class ShipmentServiceClient : IShipmentService
{
    private readonly HttpClient _httpClient;

    public ShipmentServiceClient(HttpClient httpClient)
    {
        _httpClient = httpClient;
    }

    public async Task<Shipment> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        var response = await _httpClient.GetAsync($"api/shipments/{Uri.EscapeDataString(trackingNumber)}", ct);

        if (response.StatusCode == HttpStatusCode.NotFound)
        {
            throw new KeyNotFoundException($"Shipment with tracking number '{trackingNumber}' was not found.");
        }

        response.EnsureSuccessStatusCode();

        var shipment = await response.Content.ReadFromJsonAsync<Shipment>(ct)
            ?? throw new InvalidOperationException("Received empty response from server.");

        return shipment;
    }
}

@page "/shipments/{TrackingNumber}"
@rendermode InteractiveAuto
@using sv_40f89141269a4c57b29951004fbd10e6.Client.Models
@using sv_40f89141269a4c57b29951004fbd10e6.Client.Services
@inject IShipmentService ShipmentService
@inject ILogger<ShipmentTracking> Logger
@implements IDisposable

<PageTitle>Shipment @TrackingNumber</PageTitle>

@if (_loading)
{
    <div class="loading-placeholder">
        <p>Loading shipment details for <strong>@TrackingNumber</strong>...</p>
    </div>
}
else if (_errorMessage is not null)
{
    <div class="error-container">
